parameters.content:
/**
 * Priority-based notification router.
 *
 * Routes notifications to a single channel based on priority:
 *   - urgent → SMS
 *   - normal → email
 *   - low    → webhook
 *
 * This replaces the previous broadcast approach where all channels
 * received every notification.
 */

import type { NotificationPriority } from '../events/event-types.js';
import type { Notification, NotificationChannel } from './notification.service.js';
import { Logger } from '../utils/logger.js';

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');
  private channelMap = new Map<NotificationPriority, NotificationChannel>();

  /**
   * Register a channel for a specific priority level.
   * Each priority maps to exactly one channel.
   */
  registerRoute(priority: NotificationPriority, channel: NotificationChannel): void {
    this.channelMap.set(priority, channel);
    this.logger.info(`Registered channel "${channel.name}" for priority "${priority}"`);
  }

  /**
   * Route a notification to the appropriate channel based on priority.
   * Returns true if a matching channel was found and the notification was sent.
   */
  route(priority: NotificationPriority, notification: Notification): boolean {
    const channel = this.channelMap.get(priority);
    if (!channel) {
      this.logger.info(`No channel registered for priority "${priority}", notification ${notification.id} not delivered`);
      return false;
    }
    channel.send(notification);
    this.logger.info(
      `Routed notification ${notification.id} (priority: ${priority}) to ${channel.name}`,
    );
    return true;
  }

  /**
   * Get the channel registered for a given priority.
   */
  getChannelForPriority(priority: NotificationPriority): NotificationChannel | undefined {
    return this.channelMap.get(priority);
  }
}

